{
  "main_section": "https://www.legislation.gov.uk/ukpga/2010/15/section/29",
  "type": "PROHIBITED",
  "for": "A person (a “service-provider”) concerned with the provision of a service to the public or a section of the public (for payment or not)",
  "to": "discriminate against a person requiring the service by not providing the person with the service",
  "conditions": [
    {
      "type": "UNLESS",
      "text": "this applies to the protected characteristic of— (a) age, so far as relating to persons who have not attained the age of 18; (b) marriage and civil partnership",
      "section": "https://www.legislation.gov.uk/ukpga/2010/15/section/28"
    },
    {
      "type": "UNLESS",
      "text": "this applies to discrimination, harassment or victimisation— (a) that is prohibited by Part 4 (premises), 5 (work) or 6 (education), or (b) that would be so prohibited but for an express exception",
      "section": "https://www.legislation.gov.uk/ukpga/2010/15/section/29"
    },
    {
      "type": "UNLESS",
      "text": "this applies to — (a) a breach of an equality clause or rule; (b) anything that would be a breach of an equality clause or rule but for section 69 or Part 2 of Schedule 7; (c) a breach of a non-discrimination rule",
      "section": "https://www.legislation.gov.uk/ukpga/2010/15/section/28"
    }
  ],
  "_alt_section_urls": [
    "https://www.legislation.gov.uk/ukpga/2010/15/section/29"
  ]
}

